JWT_ISSUER = os.getenv("JWT_ISSUER", APP_NAME)
JWT_AUDIENCE = os.getenv("JWT_AUDIENCE", DOMAIN)
JWT_TTL_SECONDS = int(os.getenv("JWT_TTL_SECONDS", "3600"))
NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
MAX_SKEW_SECONDS = int(os.getenv("MAX_SKEW_SECONDS", "120"))

