nonces: Dict[str, Dict[str, Any]] = {}
revoked_jti: Dict[str, float] = {}


def _now() -> int:
    return int(time.time())


def _b64url_encode(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b"=").decode("ascii")


def _b64url_decode(data: str) -> bytes:
    pad = "=" * (-len(data) % 4)
    return base64.urlsafe_b64decode((data + pad).encode("ascii"))


def _jwt_sign(payload: Dict[str, Any]) -> str:
    header = {"alg": "HS256", "typ": "JWT"}
    header_b64 = _b64url_encode(json.dumps(header, separators=(",", ":"), sort_keys=True).encode("utf-8"))
    payload_b64 = _b64url_encode(json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8"))
    signing_input = f"{header_b64}.{payload_b64}".encode("ascii")
    sig = hmac.new(JWT_SECRET.encode("utf-8"), signing_input, hashlib.sha256).digest()
    return f"{header_b64}.{payload_b64}.{_b64url_encode(sig)}"


def _jwt_verify(token: str) -> Dict[str, Any]:
    try:
        header_b64, payload_b64, sig_b64 = token.split(".")
    except ValueError:
        raise HTTPException(status_code=401, detail="Invalid token format")

    signing_input = f"{header_b64}.{payload_b64}".encode("ascii")
    expected = hmac.new(JWT_SECRET.encode("utf-8"), signing_input, hashlib.sha256).digest()
    actual = _b64url_decode(sig_b64)
    if not hmac.compare_digest(expected, actual):
        raise HTTPException(status_code=401, detail="Invalid token signature")

    try:
        payload = json.loads(_b64url_decode(payload_b64).decode("utf-8"))
    except Exception:
        raise HTTPException(status_code=401, detail="Invalid token payload")

    now = _now()
    if payload.get("iss") != JWT_ISSUER:
        raise HTTPException(status_code=401, detail="Invalid token issuer")
    if payload.get("aud") != JWT_AUDIENCE:
        raise HTTPException(status_code=401, detail="Invalid token audience")
    if "exp" not in payload or now >= int(payload["exp"]):
        raise HTTPException(status_code=401, detail="Token expired")
    if "nbf" in payload and now < int(payload["nbf"]):
        raise HTTPException(status_code=401, detail="Token not active")
    if "iat" in payload and now + MAX_SKEW_SECONDS < int(payload["iat"]):
        raise HTTPException(status_code=401, detail="Token issued in the future")
    jti = payload.get("jti")
    if jti and jti in revoked_jti and revoked_jti[jti] > now:
        raise HTTPException(status_code=401, detail="Token revoked")

    return payload


def _cleanup():
    now = _now()
    expired_nonces = [k for k, v in nonces.items() if v.get("exp", 0) <= now]
