@app.post("/auth/nonce", response_model=NonceResponse)
def get_nonce(req: NonceRequest):
    address = _normalize_address(req.address)
    chain_id = int(req.chain_id) if req.chain_id is not None else CHAIN_ID

    nonce = secrets.token_urlsafe(16)
    issued_at = _now()
    exp = issued_at + NONCE_TTL_SECONDS

    message = _build_login_message(address, nonce, issued_at, chain_id)

    nonces[address.lower()] = {
        "nonce": nonce,
        "iat": issued_at,
        "exp": exp,
        "chain_id": chain_id,
        "message": message,
        "used": False,
    }

    return NonceResponse(
        address=address,
        chain_id=chain_id,
        nonce=nonce,
        issued_at=issued_at,
        expires_at=exp,
        message=message,
    )


@app.post("/auth/verify", response_model=VerifyResponse)
def verify_signature(req: VerifyRequest):
    address = _normalize_address(req.address)
    chain_id = int(req.chain_id) if req.chain_id is not None else CHAIN_ID

    session = nonces.get(address.lower())
    if req.message is None:
        if not session:
            raise HTTPException(status_code=400, detail="No nonce session for address")
        if session.get("used"):
            raise HTTPException(status_code=400, detail="Nonce already used")
        if session.get("exp", 0) <= _now():
            raise HTTPException(status_code=400, detail="Nonce expired")
        if session.get("chain_id") != chain_id:
            raise HTTPException(status_code=400, detail="Chain ID mismatch")
        if not req.nonce or req.nonce != session.get("nonce"):
            raise HTTPException(status_code=400, detail="Nonce mismatch")
        message = session.get("message")
        if not message:
            raise HTTPException(status_code=400, detail="Missing message in session")
    else:
        message = req.message
        if session:
            if session.get("used"):
                raise HTTPException(status_code=400, detail="Nonce already used")
            if session.get("exp", 0) <= _now():
                raise HTTPException(status_code=400, detail="Nonce expired")
            if session.get("chain_id") != chain_id:
                raise HTTPException(status_code=400, detail="Chain ID mismatch")
            if req.nonce and req.nonce != session.get("nonce"):
                raise HTTPException(status_code=400, detail="Nonce mismatch")

    recovered = _recover_address(message, req.signature)
    if recovered.lower() != address.lower():
        raise HTTPException(status_code=401, detail="Recovered address does not match")

    if session:
        session["used"] = True

    now = _now()
    exp = now + JWT_TTL_SECONDS
    jti = secrets.token_urlsafe(16)
    payload = {
        "iss": JWT_ISSUER,
        "aud": JWT_AUDIENCE,
        "sub": address,
        "iat": now,
        "nbf": now - 1,
        "exp": exp,
        "jti": jti,
        "chain_id": chain_id,
    }
    token = _jwt_sign(payload)

    return VerifyResponse(authenticated=True, address=address, token=token, expires_at=exp)


@app.post("/auth/logout")
def logout(payload: Dict[str, Any] = Depends(_auth_bearer)):
    now = _now()
    exp = int(payload.get("exp", now))
    jti = payload.get("jti")
    if jti:
        revoked_jti[jti] = exp
    return {"ok": True}


